module.exports = (req, res) => {
  res.setHeader("Content-Type", "text/html; charset=utf-8");
  res.status(200).send("<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>Gastos de Baja Cuantía</title>\n<script src=\"https://api.bitrix24.com/api/v1/\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.8.2/jspdf.plugin.autotable.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js\"></script>\n<style>\n  :root {\n    --primary: #1b2a4a;\n    --primary-dark: #0e1830;\n    --accent: #c9a227;\n    --accent-dark: #a2811c;\n    --danger: #e64a4a;\n    --success: #3cb96a;\n    --bg: #f1f3f7;\n    --border: #dde2ea;\n    --text: #202b3d;\n  }\n  * { box-sizing: border-box; }\n  body {\n    margin: 0;\n    font-family: -apple-system, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\n    background: var(--bg);\n    color: var(--text);\n  }\n  .wrap { max-width: 900px; margin: 0 auto; padding: 22px 18px 60px; }\n\n  .app-header {\n    position: fixed; top: 0; left: 0; right: 0; height: 56px; z-index: 1000;\n    background: var(--primary); color: #fff; display: flex; align-items: center; gap: 6px;\n    padding: 0 6px 0 4px; box-shadow: 0 1px 6px rgba(0,0,0,0.18);\n  }\n  .menu-toggle {\n    width: 44px; height: 44px; flex: none; margin: 0; padding: 0; background: none; border: none;\n    color: #fff; display: flex; align-items: center; justify-content: center; cursor: pointer; border-radius: 6px;\n  }\n  .menu-toggle:hover { background: rgba(255,255,255,0.12); }\n  .menu-toggle svg { width: 22px; height: 22px; }\n  .app-header-title { display: flex; flex-direction: column; justify-content: center; line-height: 1.25; overflow: hidden; }\n  .app-header-title strong { font-size: 15.5px; font-weight: 700; letter-spacing: .1px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n  .app-header-title small { font-size: 10.5px; color: #c7d0e0; font-weight: 400; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n\n  .drawer-overlay {\n    position: fixed; inset: 0; background: rgba(10,15,30,0.45); z-index: 998;\n    opacity: 0; pointer-events: none; transition: opacity .2s ease;\n  }\n  .drawer-overlay.open { opacity: 1; pointer-events: auto; }\n\n  .app-body { display: flex; padding-top: 56px; min-height: 100vh; }\n  .drawer {\n    position: fixed; top: 56px; bottom: 0; left: 0; width: 272px; background: #fff; z-index: 999;\n    transform: translateX(-100%); transition: transform .22s ease; box-shadow: 3px 0 16px rgba(0,0,0,0.16);\n    overflow-y: auto; will-change: transform;\n  }\n  .drawer.open { transform: translateX(0) !important; }\n  .drawer-nav { list-style: none; margin: 0; padding: 10px 0; }\n  .drawer-nav .tab {\n    display: flex; align-items: center; gap: 13px; padding: 13px 22px; font-size: 14.5px;\n    color: #46536b; cursor: pointer; user-select: none; border-left: 3px solid transparent;\n  }\n  .drawer-nav .tab svg { width: 19px; height: 19px; flex: none; opacity: .8; }\n  .drawer-nav .tab:hover { background: #f4f6fa; }\n  .drawer-nav .tab.active {\n    background: #eef1f9; border-left-color: var(--accent); color: var(--primary); font-weight: 700;\n  }\n  .drawer-nav .tab.active svg { opacity: 1; color: var(--accent-dark); }\n  .drawer-nav .tab.hidden { display: none; }\n\n  .app-main { flex: 1; min-width: 0; }\n\n  @media (min-width: 900px) {\n    .menu-toggle { display: none; }\n    .drawer-overlay { display: none; }\n    .drawer {\n      position: sticky; top: 56px; transform: none; height: calc(100vh - 56px);\n      box-shadow: none; border-right: 1px solid var(--border); flex: none;\n    }\n    .app-header-title strong { font-size: 17px; }\n  }\n\n  .card {\n    background: #fff; border: 1px solid var(--border); border-radius: 8px;\n    padding: 20px; margin-bottom: 16px;\n  }\n  label { display: block; font-size: 13px; font-weight: 600; margin: 14px 0 6px; }\n  label:first-child { margin-top: 0; }\n  input, textarea, select {\n    width: 100%; padding: 11px 10px; border: 1px solid var(--border); border-radius: 6px;\n    font-size: 16px; font-family: inherit; background: #fff; color: var(--text);\n  }\n  input[readonly] { background: var(--bg); color: #6b7a86; }\n  textarea { min-height: 70px; resize: vertical; }\n  .row { display: flex; gap: 12px; }\n  .row > div { flex: 1; min-width: 0; }\n  button {\n    background: var(--primary); color: #fff; border: none; border-radius: 6px;\n    padding: 13px 18px; font-size: 16px; font-weight: 600; cursor: pointer; margin-top: 18px;\n    width: 100%;\n  }\n  button:hover { background: var(--primary-dark); }\n  button:disabled { background: #b9c2c9; cursor: not-allowed; }\n  button.secondary { background: #fff; color: var(--text); border: 1px solid var(--border); }\n  button.secondary:hover { background: var(--bg); }\n  .btn-row { display: flex; gap: 10px; }\n  .btn-row button { margin-top: 10px; width: auto; flex: 1; }\n\n  .msg { padding: 12px 14px; border-radius: 6px; font-size: 13.5px; margin-top: 14px; display: none; line-height: 1.5; }\n  .msg.error { background: #fdecec; color: #a92626; display: block; }\n  .msg.success { background: #e8f8ee; color: #1f7a41; display: block; }\n  .msg.info { background: #eaf6fd; color: #1a6f8f; display: block; }\n  .loading { color: #6b7a86; font-size: 13px; }\n  .empty-state { text-align: center; padding: 40px 20px; color: #6b7a86; font-size: 14px; }\n\n  .user-list { max-height: 360px; overflow-y: auto; border: 1px solid var(--border); border-radius: 6px; }\n  .user-row {\n    display: flex; align-items: center; gap: 10px; padding: 9px 12px;\n    border-bottom: 1px solid var(--border); font-size: 14px;\n  }\n  .user-row:last-child { border-bottom: none; }\n  .user-row input[type=\"checkbox\"] { width: auto; flex: none; }\n  .user-row span { flex: 1; }\n  .search-box { margin-bottom: 10px; }\n\n  .combo-wrap { position: relative; }\n  .combo-dropdown {\n    display: none; position: absolute; left: 0; right: 0; top: 100%; z-index: 50;\n    background: #fff; border: 1px solid var(--border); border-radius: 6px; margin-top: 4px;\n    max-height: 220px; overflow-y: auto; box-shadow: 0 4px 14px rgba(0,0,0,0.16);\n  }\n  .combo-dropdown.open { display: block; }\n  .combo-option { padding: 9px 12px; font-size: 14px; cursor: pointer; }\n  .combo-option:hover, .combo-option.active { background: var(--bg); }\n  .combo-empty { padding: 9px 12px; font-size: 13px; color: #6b7a86; }\n\n  .section-title { font-size: 14px; font-weight: 700; margin: 6px 0 10px; color: var(--primary-dark); }\n\n  .gasto-item { border: 1px solid var(--border); border-radius: 8px; padding: 12px; margin-bottom: 10px; }\n  .gasto-item .gasto-top { display: flex; justify-content: space-between; align-items: baseline; gap: 8px; flex-wrap: wrap; }\n  .gasto-item .gasto-total { font-size: 17px; font-weight: 700; color: var(--primary-dark); }\n  .gasto-item .gasto-line { font-size: 13px; color: #4a5a66; margin: 3px 0; }\n  .gasto-item .gasto-actions { display: flex; gap: 8px; margin-top: 10px; flex-wrap: wrap; }\n  .gasto-item .gasto-actions button { width: auto; margin: 0; padding: 8px 14px; font-size: 13px; }\n  .gasto-item .gasto-actions .danger { background: #fff; color: var(--danger); border: 1px solid var(--danger); }\n  .badge { display: inline-block; font-size: 11px; font-weight: 600; padding: 2px 8px; border-radius: 10px; }\n  .badge.propio { background: #eaf6fd; color: #1a6f8f; }\n  .badge.ajeno { background: #f4f6fa; color: #6b7a86; }\n\n  .filters-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 12px; }\n  @media (max-width: 560px) { .filters-grid { grid-template-columns: 1fr; } }\n\n  .stat-row { display: flex; gap: 10px; flex-wrap: wrap; margin: 14px 0; }\n  .stat-box { flex: 1; min-width: 140px; background: var(--bg); border-radius: 8px; padding: 10px 14px; }\n  .stat-box .n { font-size: 18px; font-weight: 700; color: var(--primary-dark); }\n  .stat-box .l { font-size: 11.5px; color: #6b7a86; }\n\n  .table-wrap { overflow-x: auto; border: 1px solid var(--border); border-radius: 8px; }\n  table.data-table { width: 100%; border-collapse: collapse; font-size: 12.5px; white-space: nowrap; }\n  table.data-table th, table.data-table td { border-bottom: 1px solid var(--border); padding: 7px 9px; text-align: left; }\n  table.data-table th { background: #f4f6f8; font-weight: 700; position: sticky; top: 0; }\n  table.data-table tr:last-child td { border-bottom: none; }\n\n  .info-box { display: flex; gap: 10px; background: #eaf6fd; border: 1px solid #bfe1ef; border-radius: 8px; padding: 12px 14px; font-size: 13px; color: #1a6f8f; line-height: 1.55; margin-bottom: 14px; }\n  .info-box ul { margin: 6px 0 0; padding-left: 18px; }\n\n  .excel-row { display: flex; align-items: center; gap: 10px; padding: 8px 4px; border-bottom: 1px solid var(--border); font-size: 12.5px; }\n  .excel-row:last-child { border-bottom: none; }\n  .excel-row .dot { width: 9px; height: 9px; border-radius: 50%; flex: none; }\n  .excel-row .dot.ok { background: var(--success); }\n  .excel-row .dot.error { background: var(--danger); }\n  .excel-row .txt { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; }\n  .excel-row .motivo { color: var(--danger); }\n\n  .map-modal {\n    display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.5);\n    z-index: 9999; align-items: center; justify-content: center; padding: 12px;\n  }\n  .map-modal.open { display: flex; }\n  .map-modal-content { background: #fff; border-radius: 10px; width: 100%; max-width: 420px; max-height: 92vh; overflow: auto; padding: 16px; }\n  .map-modal-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }\n  .map-modal-header b { font-size: 16px; }\n  .confirm-modal-msg { font-size: 14px; line-height: 1.55; color: var(--text); white-space: pre-line; }\n  .map-actions { display: flex; gap: 8px; margin-top: 12px; }\n  .map-actions button { margin: 0; }\n  .map-actions .cancel { background: #fff; color: var(--text); border: 1px solid var(--border); }\n  .map-actions .danger-solid { background: var(--danger); }\n  .map-actions .danger-solid:hover { background: #c73a3a; }\n\n  @media (max-width: 480px) {\n    .wrap { padding: 14px 12px 40px; }\n    .card { padding: 14px; }\n    .row { flex-direction: column; gap: 0; }\n    .drawer { width: 84vw; max-width: 300px; }\n    .user-row { padding: 12px; flex-wrap: wrap; }\n    .user-row input[type=\"checkbox\"] { width: 20px; height: 20px; }\n  }\n</style>\n</head>\n<body>\n<header class=\"app-header\">\n  <button type=\"button\" id=\"menuToggle\" class=\"menu-toggle\" aria-label=\"Abrir menú\">\n    <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><line x1=\"3\" y1=\"6\" x2=\"21\" y2=\"6\"/><line x1=\"3\" y1=\"12\" x2=\"21\" y2=\"12\"/><line x1=\"3\" y1=\"18\" x2=\"21\" y2=\"18\"/></svg>\n  </button>\n  <div class=\"app-header-title\">\n    <strong>Gastos de Baja Cuantía</strong>\n    <small>Registro y control de compras</small>\n  </div>\n</header>\n\n<div id=\"drawerOverlay\" class=\"drawer-overlay\"></div>\n\n<div class=\"app-body\">\n  <nav id=\"drawer\" class=\"drawer\">\n    <ul class=\"drawer-nav\">\n      <li class=\"tab hidden\" id=\"tabRegistrarBtn\" data-tab=\"registrar\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 5v14M5 12h14\"/></svg>\n        <span>Registrar gasto</span>\n      </li>\n      <li class=\"tab hidden\" id=\"tabExcelBtn\" data-tab=\"excel\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z\"/><path d=\"M14 2v6h6\"/></svg>\n        <span>Cargar desde Excel</span>\n      </li>\n      <li class=\"tab hidden\" id=\"tabHistorialBtn\" data-tab=\"historial\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"8\" y1=\"6\" x2=\"21\" y2=\"6\"/><line x1=\"8\" y1=\"12\" x2=\"21\" y2=\"12\"/><line x1=\"8\" y1=\"18\" x2=\"21\" y2=\"18\"/><circle cx=\"3.6\" cy=\"6\" r=\"1.2\" fill=\"currentColor\" stroke=\"none\"/><circle cx=\"3.6\" cy=\"12\" r=\"1.2\" fill=\"currentColor\" stroke=\"none\"/><circle cx=\"3.6\" cy=\"18\" r=\"1.2\" fill=\"currentColor\" stroke=\"none\"/></svg>\n        <span>Historial</span>\n      </li>\n      <li class=\"tab hidden\" id=\"tabReportesBtn\" data-tab=\"reportes\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M3 3v18h18\"/><path d=\"M7 15l4-4 3 3 5-6\"/></svg>\n        <span>Reportes</span>\n      </li>\n      <li class=\"tab hidden\" id=\"tabConfigBtn\" data-tab=\"config\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19.4 15a1.7 1.7 0 0 0 .3 1.9l.1.1a2 2 0 1 1-2.8 2.8l-.1-.1a1.7 1.7 0 0 0-1.9-.3 1.7 1.7 0 0 0-1 1.5V21a2 2 0 1 1-4 0v-.1a1.7 1.7 0 0 0-1-1.6 1.7 1.7 0 0 0-1.9.3l-.1.1a2 2 0 1 1-2.8-2.8l.1-.1a1.7 1.7 0 0 0 .3-1.9 1.7 1.7 0 0 0-1.5-1H3a2 2 0 1 1 0-4h.1a1.7 1.7 0 0 0 1.6-1 1.7 1.7 0 0 0-.3-1.9l-.1-.1a2 2 0 1 1 2.8-2.8l.1.1a1.7 1.7 0 0 0 1.9.3H9a1.7 1.7 0 0 0 1-1.5V3a2 2 0 1 1 4 0v.1a1.7 1.7 0 0 0 1 1.5 1.7 1.7 0 0 0 1.9-.3l.1-.1a2 2 0 1 1 2.8 2.8l-.1.1a1.7 1.7 0 0 0-.3 1.9V9a1.7 1.7 0 0 0 1.5 1H21a2 2 0 1 1 0 4h-.1a1.7 1.7 0 0 0-1.5 1z\"/></svg>\n        <span>Configurar usuarios</span>\n      </li>\n    </ul>\n  </nav>\n\n  <main class=\"app-main\">\n  <div class=\"wrap\">\n\n    <div id=\"viewSinAcceso\" class=\"card\" style=\"display:none\">\n      <div class=\"empty-state\">\n        <p><strong>No tienes acceso a esta app todavía.</strong></p>\n        <p>Pide a un administrador del portal que te autorice desde \"Configurar usuarios\" para poder registrar gastos de baja cuantía.</p>\n      </div>\n    </div>\n\n    <div id=\"viewInicioLoading\" class=\"card loading\">Cargando...</div>\n\n    <!-- ---- Registrar gasto ---- -->\n    <div id=\"viewRegistrar\" class=\"card\" style=\"display:none\">\n      <div class=\"section-title\" id=\"registrarTitulo\">Registrar gasto</div>\n      <form id=\"formGasto\">\n        <label for=\"gFecha\">Fecha *</label>\n        <input type=\"date\" id=\"gFecha\" required />\n\n        <label for=\"gMes\">Mes</label>\n        <input type=\"text\" id=\"gMes\" readonly />\n\n        <label for=\"gNumeroDocumento\">N° de documento *</label>\n        <input type=\"text\" id=\"gNumeroDocumento\" placeholder=\"Número de factura, CF o ticket\" required maxlength=\"60\" />\n\n        <label for=\"gProveedor\">Proveedor *</label>\n        <input type=\"text\" id=\"gProveedor\" list=\"gProveedorList\" placeholder=\"Nombre del proveedor\" required maxlength=\"150\" />\n        <datalist id=\"gProveedorList\"></datalist>\n\n        <label for=\"gDescripcion\">Descripción *</label>\n        <textarea id=\"gDescripcion\" placeholder=\"Descripción de la compra\" required></textarea>\n\n        <label for=\"gAreaSolicitante\">Área solicitante *</label>\n        <div class=\"combo-wrap\">\n          <input type=\"text\" id=\"gAreaSolicitante\" placeholder=\"Escribe para buscar una unidad/dependencia...\" required maxlength=\"150\" autocomplete=\"off\" />\n          <div id=\"gAreaDropdown\" class=\"combo-dropdown\"></div>\n        </div>\n\n        <div class=\"row\">\n          <div>\n            <label for=\"gMontoRetenido\">Monto retenido</label>\n            <input type=\"number\" id=\"gMontoRetenido\" step=\"0.01\" min=\"0\" value=\"0\" />\n          </div>\n          <div>\n            <label for=\"gMontoTotal\">Monto total *</label>\n            <input type=\"number\" id=\"gMontoTotal\" step=\"0.01\" min=\"0\" required />\n          </div>\n        </div>\n\n        <div class=\"btn-row\">\n          <button type=\"submit\" id=\"btnGuardarGasto\">Registrar gasto</button>\n          <button type=\"button\" id=\"btnCancelarEdicion\" class=\"secondary\" style=\"display:none\">Cancelar edición</button>\n        </div>\n        <div id=\"gastoMsg\" class=\"msg\"></div>\n      </form>\n    </div>\n\n    <!-- ---- Cargar desde Excel ---- -->\n    <div id=\"viewExcel\" class=\"card\" style=\"display:none\">\n      <div class=\"section-title\">Carga masiva desde Excel</div>\n      <div class=\"info-box\">\n        El archivo debe tener estas columnas en la primera fila (en cualquier orden):\n        <ul>\n          <li><b>fecha</b> — formato día/mes/año, ej. 01/01/2023 (celda en formato TEXTO)</li>\n          <li><b>mes</b> — número 1 a 12 (opcional, se recalcula desde la fecha)</li>\n          <li><b>numero_documento</b> — número de factura, CF o ticket</li>\n          <li><b>proveedor</b> — nombre del proveedor</li>\n          <li><b>descripcion</b> — descripción de la compra</li>\n          <li><b>area_solicitante</b> — nombre del área solicitante, igual al registrado en sistema</li>\n          <li><b>monto_retenido</b> — si no aplica, ingrese 0</li>\n          <li><b>monto_total</b> — total de la compra según documento</li>\n        </ul>\n      </div>\n      <input type=\"file\" id=\"gExcelFile\" accept=\".xlsx,.xls,.csv\" />\n      <button type=\"button\" id=\"btnProcesarExcel\">Procesar archivo</button>\n      <div id=\"excelResumen\" class=\"stat-row\" style=\"display:none\"></div>\n      <div id=\"excelPreviewWrap\" style=\"display:none\">\n        <div class=\"section-title\" style=\"margin-top:16px\">Detalle por fila</div>\n        <div id=\"excelPreview\" class=\"table-wrap\" style=\"max-height:320px; overflow-y:auto\"></div>\n        <button type=\"button\" id=\"btnConfirmarExcel\" style=\"display:none\">Confirmar e importar</button>\n      </div>\n      <div id=\"excelMsg\" class=\"msg\"></div>\n    </div>\n\n    <!-- ---- Historial ---- -->\n    <div id=\"viewHistorial\" class=\"card\" style=\"display:none\">\n      <div class=\"section-title\">Historial de gastos</div>\n      <div id=\"historialFiltroAdmin\" class=\"btn-row\" style=\"display:none; margin-bottom:6px\">\n        <button type=\"button\" id=\"btnVerTodos\" class=\"secondary\">Todos</button>\n        <button type=\"button\" id=\"btnVerMios\" class=\"secondary\">Solo los míos</button>\n      </div>\n\n      <div class=\"filters-grid\" style=\"margin-bottom:10px\">\n        <div>\n          <label for=\"hFechaDesde\">Fecha desde</label>\n          <input type=\"date\" id=\"hFechaDesde\" />\n        </div>\n        <div>\n          <label for=\"hFechaHasta\">Fecha hasta</label>\n          <input type=\"date\" id=\"hFechaHasta\" />\n        </div>\n        <div>\n          <label for=\"hMes\">Mes</label>\n          <select id=\"hMes\">\n            <option value=\"\">Todos</option>\n            <option value=\"1\">1 - Enero</option>\n            <option value=\"2\">2 - Febrero</option>\n            <option value=\"3\">3 - Marzo</option>\n            <option value=\"4\">4 - Abril</option>\n            <option value=\"5\">5 - Mayo</option>\n            <option value=\"6\">6 - Junio</option>\n            <option value=\"7\">7 - Julio</option>\n            <option value=\"8\">8 - Agosto</option>\n            <option value=\"9\">9 - Septiembre</option>\n            <option value=\"10\">10 - Octubre</option>\n            <option value=\"11\">11 - Noviembre</option>\n            <option value=\"12\">12 - Diciembre</option>\n          </select>\n        </div>\n        <div id=\"hRegistradoPorWrap\" style=\"display:none\">\n          <label for=\"hRegistradoPor\">Registrado por</label>\n          <select id=\"hRegistradoPor\"><option value=\"\">Todos</option></select>\n        </div>\n        <div>\n          <label for=\"hNumeroDocumento\">N° de documento</label>\n          <input type=\"text\" id=\"hNumeroDocumento\" placeholder=\"Buscar...\" />\n        </div>\n        <div>\n          <label for=\"hProveedor\">Proveedor</label>\n          <input type=\"text\" id=\"hProveedor\" placeholder=\"Buscar...\" />\n        </div>\n        <div>\n          <label for=\"hDescripcion\">Descripción</label>\n          <input type=\"text\" id=\"hDescripcion\" placeholder=\"Buscar...\" />\n        </div>\n        <div>\n          <label for=\"hAreaSolicitante\">Área solicitante</label>\n          <input type=\"text\" id=\"hAreaSolicitante\" placeholder=\"Buscar...\" />\n        </div>\n        <div>\n          <label for=\"hMontoTotalMin\">Monto total mínimo</label>\n          <input type=\"number\" id=\"hMontoTotalMin\" step=\"0.01\" min=\"0\" />\n        </div>\n        <div>\n          <label for=\"hMontoTotalMax\">Monto total máximo</label>\n          <input type=\"number\" id=\"hMontoTotalMax\" step=\"0.01\" min=\"0\" />\n        </div>\n        <div>\n          <label for=\"hMontoRetenidoMin\">Monto retenido mínimo</label>\n          <input type=\"number\" id=\"hMontoRetenidoMin\" step=\"0.01\" min=\"0\" />\n        </div>\n        <div>\n          <label for=\"hMontoRetenidoMax\">Monto retenido máximo</label>\n          <input type=\"number\" id=\"hMontoRetenidoMax\" step=\"0.01\" min=\"0\" />\n        </div>\n      </div>\n      <div class=\"btn-row\" style=\"margin-bottom:10px\">\n        <button type=\"button\" id=\"btnAplicarFiltrosHistorial\">Aplicar filtros</button>\n        <button type=\"button\" id=\"btnLimpiarFiltrosHistorial\" class=\"secondary\">Limpiar filtros</button>\n      </div>\n\n      <div id=\"historialLoading\" class=\"loading\">Cargando...</div>\n      <div id=\"historialContent\" style=\"display:none\"></div>\n    </div>\n\n    <!-- ---- Reportes ---- -->\n    <div id=\"viewReportes\" class=\"card\" style=\"display:none\">\n      <div class=\"section-title\">Reportes</div>\n      <div id=\"reportesLoading\" class=\"loading\">Cargando...</div>\n      <div id=\"reportesContent\" style=\"display:none\">\n        <div class=\"filters-grid\">\n          <div>\n            <label for=\"repUsuario\">Nombre</label>\n            <select id=\"repUsuario\"><option value=\"\">Todos</option></select>\n          </div>\n          <div>\n            <label for=\"repCargo\">Cargo</label>\n            <select id=\"repCargo\"><option value=\"\">Todos</option></select>\n          </div>\n          <div>\n            <label for=\"repUnidad\">Unidad</label>\n            <select id=\"repUnidad\"><option value=\"\">Todas</option></select>\n          </div>\n          <div></div>\n          <div>\n            <label for=\"repDesde\">Fecha desde</label>\n            <input type=\"date\" id=\"repDesde\" />\n          </div>\n          <div>\n            <label for=\"repHasta\">Fecha hasta</label>\n            <input type=\"date\" id=\"repHasta\" />\n          </div>\n        </div>\n        <button type=\"button\" id=\"btnAplicarFiltros\">Aplicar filtros</button>\n\n        <div id=\"repStats\" class=\"stat-row\"></div>\n\n        <div class=\"btn-row\">\n          <button type=\"button\" id=\"btnExportExcel\" class=\"secondary\">Descargar Excel</button>\n          <button type=\"button\" id=\"btnExportPDF\" class=\"secondary\">Descargar PDF</button>\n        </div>\n\n        <div class=\"table-wrap\" style=\"margin-top:14px; max-height:420px; overflow-y:auto\">\n          <table class=\"data-table\" id=\"repTable\">\n            <thead>\n              <tr>\n                <th>Fecha</th><th>N° Doc</th><th>Proveedor</th><th>Descripción</th><th>Área solicitante</th>\n                <th>Retenido</th><th>Total</th><th>Registrado por</th><th>Cargo</th><th>Unidad</th>\n              </tr>\n            </thead>\n            <tbody id=\"repTableBody\"></tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <!-- ---- Configurar usuarios / Fondos ---- -->\n    <div id=\"viewConfig\" class=\"card\" style=\"display:none\">\n      <div class=\"section-title\">Crear fondo</div>\n      <div class=\"row\">\n        <div>\n          <label for=\"fTipo\">Tipo de fondo</label>\n          <select id=\"fTipo\">\n            <option value=\"caja_chica\">Fondo de caja chica</option>\n            <option value=\"circulante\">Fondo circulante</option>\n          </select>\n        </div>\n        <div>\n          <label for=\"fMontoTotal\">Monto total ($)</label>\n          <input type=\"number\" id=\"fMontoTotal\" step=\"0.01\" min=\"0\" placeholder=\"0.00\" />\n        </div>\n        <div>\n          <label for=\"fAnio\">Año</label>\n          <select id=\"fAnio\"></select>\n        </div>\n      </div>\n      <button type=\"button\" id=\"btnCrearFondo\">Crear fondo</button>\n      <div id=\"fondoMsg\" class=\"msg\"></div>\n\n      <div class=\"section-title\" style=\"margin-top:22px\">Fondos creados</div>\n      <div id=\"fondosLoading\" class=\"loading\">Cargando...</div>\n      <div id=\"fondosContent\" style=\"display:none\"></div>\n    </div>\n\n    <!-- Modal: asignar usuarios a un fondo -->\n    <div id=\"asignarModal\" class=\"map-modal\">\n      <div class=\"map-modal-content\" style=\"max-width:480px\">\n        <div class=\"map-modal-header\">\n          <b id=\"asignarModalTitle\">Asignar administrador</b>\n        </div>\n        <div class=\"search-box\">\n          <input type=\"text\" id=\"asignarUserSearch\" placeholder=\"Buscar usuario...\" />\n        </div>\n        <div id=\"asignarUserList\" class=\"user-list\"></div>\n        <div id=\"asignarModalMsg\" class=\"msg\"></div>\n        <div class=\"map-actions\">\n          <button type=\"button\" class=\"cancel\" id=\"asignarModalCancel\">Cancelar</button>\n          <button type=\"button\" id=\"asignarModalGuardar\">Guardar</button>\n        </div>\n      </div>\n    </div>\n\n  </div>\n  </main>\n</div>\n\n<div id=\"confirmModal\" class=\"map-modal\">\n  <div class=\"map-modal-content\" style=\"max-width:400px\">\n    <div class=\"map-modal-header\">\n      <b id=\"confirmModalTitle\">Confirmar acción</b>\n    </div>\n    <div id=\"confirmModalMsg\" class=\"confirm-modal-msg\"></div>\n    <div class=\"map-actions\">\n      <button type=\"button\" class=\"cancel\" id=\"confirmModalCancel\">Cancelar</button>\n      <button type=\"button\" id=\"confirmModalOk\">Aceptar</button>\n    </div>\n  </div>\n</div>\n\n<script>\n(function () {\n  var currentUser = null;\n  var isAdmin = false;\n  var allUsers = [];        // {ID, NAME, LAST_NAME, UF_DEPARTMENT, WORK_POSITION}\n  var allDepartments = [];  // {ID, NAME}\n  var departamentosError = null; // detalle del error si department.get falla (permiso/scope)\n  var autorizadosIds = [];  // string[] Bitrix user IDs que pueden cargar gastos\n  var canLoad = false;\n  var editingId = null;\n\n  var todosLosGastos = [];      // cache para Reportes (solo admin)\n  var gastosFiltrados = [];\n  var filasExcelValidas = [];   // filas listas para importar tras procesar el archivo\n\n  function esc(s) {\n    return String(s == null ? '' : s).replace(/[&<>\"']/g, function (c) {\n      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '\"': '&quot;', \"'\": '&#39;' }[c];\n    });\n  }\n  function money(n) { return (Number(n) || 0).toFixed(2); }\n  function todayStr() { return new Date().toISOString().slice(0, 10); }\n  function fullName(u) { return [u.NAME, u.LAST_NAME].filter(Boolean).join(' ') || ('Usuario #' + u.ID); }\n\n  function findUser(id) { return allUsers.find(function (u) { return String(u.ID) === String(id); }); }\n  function nombreDe(id) { var u = findUser(id); return u ? fullName(u) : ('Usuario #' + id); }\n  function getCargo(id) { var u = findUser(id); return (u && u.WORK_POSITION) ? u.WORK_POSITION : '—'; }\n  function getUnidad(id) {\n    var u = findUser(id);\n    if (!u || !u.UF_DEPARTMENT || !u.UF_DEPARTMENT.length) return '—';\n    var d = allDepartments.find(function (x) { return String(x.ID) === String(u.UF_DEPARTMENT[0]); });\n    return d ? (d.NAME || '').replace(/[_\\s]+$/, '').trim() : '—';\n  }\n\n  // ---- BX24 helpers ----\n  function bx(method, params) {\n    return new Promise(function (resolve, reject) {\n      BX24.callMethod(method, params || {}, function (result) {\n        if (result.error()) reject(result.error()); else resolve(result.data());\n      });\n    });\n  }\n  function bxListAll(method, params) {\n    return new Promise(function (resolve, reject) {\n      var all = [];\n      function handler(result) {\n        if (result.error()) { reject(result.error()); return; }\n        all = all.concat(result.data());\n        if (result.more()) result.next(handler); else resolve(all);\n      }\n      BX24.callMethod(method, params, handler);\n    });\n  }\n\n  // ---- API propia (Vercel + Supabase) ----\n  function apiCall(path, options) {\n    options = options || {};\n    return fetch('/api/' + path, {\n      method: options.method || 'GET',\n      headers: { 'Content-Type': 'application/json' },\n      body: options.body ? JSON.stringify(options.body) : undefined\n    }).then(function (r) { return r.json(); });\n  }\n\n  function showMsg(el, type, html) { el.className = 'msg ' + type; el.innerHTML = html; el.style.display = 'block'; }\n  function hideMsg(el) { el.style.display = 'none'; el.innerHTML = ''; }\n\n  // ---- Modal de confirmación / aviso ----\n  function showConfirmModal(message, opts) {\n    opts = opts || {};\n    return new Promise(function (resolve) {\n      var modal = document.getElementById('confirmModal');\n      var cancelBtn = document.getElementById('confirmModalCancel');\n      var okBtn = document.getElementById('confirmModalOk');\n      document.getElementById('confirmModalTitle').textContent = opts.title || (opts.alertOnly ? 'Aviso' : 'Confirmar acción');\n      document.getElementById('confirmModalMsg').textContent = message;\n      cancelBtn.style.display = opts.alertOnly ? 'none' : '';\n      okBtn.textContent = opts.okText || (opts.alertOnly ? 'Entendido' : 'Aceptar');\n      okBtn.className = opts.danger ? 'danger-solid' : '';\n      function cleanup(result) {\n        modal.classList.remove('open');\n        okBtn.removeEventListener('click', onOk);\n        cancelBtn.removeEventListener('click', onCancel);\n        resolve(result);\n      }\n      function onOk() { cleanup(true); }\n      function onCancel() { cleanup(false); }\n      okBtn.addEventListener('click', onOk);\n      cancelBtn.addEventListener('click', onCancel);\n      modal.classList.add('open');\n    });\n  }\n  function customConfirm(message, opts) { return showConfirmModal(message, opts); }\n  function customAlert(message, opts) { return showConfirmModal(message, Object.assign({}, opts, { alertOnly: true })); }\n\n  // ---- Menú lateral (drawer) ----\n  var drawerEl = document.getElementById('drawer');\n  var drawerOverlayEl = document.getElementById('drawerOverlay');\n  function openDrawer() { drawerEl.classList.add('open'); drawerOverlayEl.classList.add('open'); }\n  function closeDrawer() { drawerEl.classList.remove('open'); drawerOverlayEl.classList.remove('open'); }\n  document.getElementById('menuToggle').addEventListener('click', function () {\n    if (drawerEl.classList.contains('open')) closeDrawer(); else openDrawer();\n  });\n  drawerOverlayEl.addEventListener('click', closeDrawer);\n\n  var VIEWS = ['registrar', 'excel', 'historial', 'reportes', 'config'];\n  function activarTab(name) {\n    document.querySelectorAll('.tab').forEach(function (t) { t.classList.toggle('active', t.getAttribute('data-tab') === name); });\n    VIEWS.forEach(function (v) { document.getElementById('view' + v.charAt(0).toUpperCase() + v.slice(1)).style.display = (v === name ? 'block' : 'none'); });\n    if (window.innerWidth < 900) closeDrawer();\n    if (name === 'historial') loadHistorial();\n    if (name === 'reportes') initReportes();\n    if (name === 'config') { initConfigTab(); }\n  }\n  document.querySelectorAll('.tab').forEach(function (tab) {\n    tab.addEventListener('click', function () { activarTab(tab.getAttribute('data-tab')); });\n  });\n\n  // ==================================================================\n  // Registrar gasto\n  // ==================================================================\n  var formGasto = document.getElementById('formGasto');\n  var gFecha = document.getElementById('gFecha');\n  var gMes = document.getElementById('gMes');\n  var MESES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];\n\n  gFecha.addEventListener('change', function () {\n    if (!gFecha.value) { gMes.value = ''; return; }\n    var m = parseInt(gFecha.value.slice(5, 7), 10);\n    gMes.value = m ? (m + ' - ' + MESES[m - 1]) : '';\n  });\n\n  function limpiarFormGasto() {\n    formGasto.reset();\n    gMes.value = '';\n    document.getElementById('gMontoRetenido').value = '0';\n    editingId = null;\n    document.getElementById('registrarTitulo').textContent = 'Registrar gasto';\n    document.getElementById('btnGuardarGasto').textContent = 'Registrar gasto';\n    document.getElementById('btnCancelarEdicion').style.display = 'none';\n    prellenarAreaSolicitante();\n  }\n\n  // Por defecto sugiere la unidad/dependencia de Bitrix24 a la que pertenece\n  // quien está registrando el gasto; el campo sigue siendo editable por si\n  // necesita registrarlo a nombre de otra área.\n  function prellenarAreaSolicitante() {\n    var propia = getUnidad(currentUser.ID);\n    document.getElementById('gAreaSolicitante').value = (propia && propia !== '—') ? propia : '';\n  }\n\n  function cargarGastoEnFormulario(g) {\n    editingId = g.id;\n    gFecha.value = g.fecha;\n    gFecha.dispatchEvent(new Event('change'));\n    document.getElementById('gNumeroDocumento').value = g.numero_documento || '';\n    document.getElementById('gProveedor').value = g.proveedor || '';\n    document.getElementById('gDescripcion').value = g.descripcion || '';\n    document.getElementById('gAreaSolicitante').value = g.area_solicitante || '';\n    document.getElementById('gMontoRetenido').value = g.monto_retenido != null ? g.monto_retenido : 0;\n    document.getElementById('gMontoTotal').value = g.monto_total != null ? g.monto_total : '';\n    document.getElementById('registrarTitulo').textContent = 'Editar gasto';\n    document.getElementById('btnGuardarGasto').textContent = 'Guardar cambios';\n    document.getElementById('btnCancelarEdicion').style.display = 'block';\n    activarTab('registrar');\n  }\n  document.getElementById('btnCancelarEdicion').addEventListener('click', limpiarFormGasto);\n\n  formGasto.addEventListener('submit', function (ev) {\n    ev.preventDefault();\n    var msgEl = document.getElementById('gastoMsg');\n    hideMsg(msgEl);\n    var gasto = {\n      fecha: gFecha.value,\n      numero_documento: document.getElementById('gNumeroDocumento').value.trim(),\n      proveedor: document.getElementById('gProveedor').value.trim(),\n      descripcion: document.getElementById('gDescripcion').value.trim(),\n      area_solicitante: document.getElementById('gAreaSolicitante').value.trim(),\n      monto_retenido: document.getElementById('gMontoRetenido').value || 0,\n      monto_total: document.getElementById('gMontoTotal').value\n    };\n    var btn = document.getElementById('btnGuardarGasto');\n    btn.disabled = true;\n    apiCall('gastos', {\n      method: 'POST',\n      body: { action: 'save', id: editingId, gasto: gasto, actor_id: currentUser.ID, actor_nombre: fullName(currentUser), actor_is_admin: isAdmin }\n    }).then(function (r) {\n      btn.disabled = false;\n      if (r.ok) {\n        showMsg(msgEl, 'success', editingId ? 'Gasto actualizado correctamente.' : 'Gasto registrado correctamente.');\n        limpiarFormGasto();\n        cargarProveedores();\n      } else {\n        showMsg(msgEl, 'error', r.error || 'No se pudo guardar el gasto.');\n      }\n    }).catch(function () {\n      btn.disabled = false;\n      showMsg(msgEl, 'error', 'Error de conexión al guardar el gasto.');\n    });\n  });\n\n  var areasDisponibles = [];\n  function poblarAreasDesdeDepartamentos() {\n    areasDisponibles = Array.from(new Set(\n      allDepartments.map(function (d) { return (d.NAME || '').replace(/[_\\s]+$/, '').trim(); }).filter(Boolean)\n    )).sort();\n  }\n\n  // ---- Combo con buscador para \"Área solicitante\" ----\n  var gAreaInput = document.getElementById('gAreaSolicitante');\n  var gAreaDropdown = document.getElementById('gAreaDropdown');\n\n  function renderAreaDropdown() {\n    var filtro = gAreaInput.value.trim().toLowerCase();\n    var opciones = filtro\n      ? areasDisponibles.filter(function (a) { return a.toLowerCase().indexOf(filtro) !== -1; })\n      : areasDisponibles;\n    if (opciones.length) {\n      gAreaDropdown.innerHTML = opciones.map(function (a) { return '<div class=\"combo-option\" data-area=\"' + esc(a) + '\">' + esc(a) + '</div>'; }).join('');\n    } else if (!areasDisponibles.length) {\n      gAreaDropdown.innerHTML = '<div class=\"combo-empty\">No se pudieron cargar las unidades de Bitrix24' +\n        (departamentosError ? ' (falta el permiso \"department\" en la app)' : '') +\n        '. Puedes escribir el área manualmente.</div>';\n    } else {\n      gAreaDropdown.innerHTML = '<div class=\"combo-empty\">Sin coincidencias — puedes escribir el nombre manualmente.</div>';\n    }\n  }\n  function abrirAreaDropdown() { renderAreaDropdown(); gAreaDropdown.classList.add('open'); }\n  function cerrarAreaDropdown() { gAreaDropdown.classList.remove('open'); }\n\n  gAreaInput.addEventListener('focus', abrirAreaDropdown);\n  gAreaInput.addEventListener('input', abrirAreaDropdown);\n  gAreaDropdown.addEventListener('mousedown', function (ev) {\n    var opt = ev.target.closest('[data-area]');\n    if (!opt) return;\n    ev.preventDefault();\n    gAreaInput.value = opt.getAttribute('data-area');\n    cerrarAreaDropdown();\n  });\n  document.addEventListener('click', function (ev) {\n    if (ev.target !== gAreaInput && !gAreaDropdown.contains(ev.target)) cerrarAreaDropdown();\n  });\n\n  function cargarProveedores() {\n    apiCall('gastos?action=proveedores').then(function (r) {\n      if (!r.ok) return;\n      var dl = document.getElementById('gProveedorList');\n      dl.innerHTML = '';\n      (r.proveedores || []).forEach(function (p) {\n        var opt = document.createElement('option');\n        opt.value = p;\n        dl.appendChild(opt);\n      });\n    }).catch(function () {});\n  }\n\n  // ==================================================================\n  // Cargar desde Excel\n  // ==================================================================\n  function normalizeHeader(h) {\n    return String(h || '').trim().toLowerCase()\n      .normalize('NFD').replace(/[\\u0300-\\u036f]/g, '')\n      .replace(/\\s+/g, '_');\n  }\n  function parseFechaExcel(v) {\n    if (v == null || v === '') return null;\n    if (typeof v === 'number') {\n      var utcDays = Math.floor(v - 25569);\n      var d = new Date(utcDays * 86400 * 1000);\n      return d.toISOString().slice(0, 10);\n    }\n    var s = String(v).trim();\n    var m = /^(\\d{1,2})[\\/\\-](\\d{1,2})[\\/\\-](\\d{4})$/.exec(s);\n    if (m) return m[3] + '-' + ('0' + m[2]).slice(-2) + '-' + ('0' + m[1]).slice(-2);\n    if (/^\\d{4}-\\d{2}-\\d{2}$/.test(s)) return s;\n    return null;\n  }\n  function numExcel(v) {\n    if (v === '' || v == null) return null;\n    var n = parseFloat(String(v).replace(',', '.'));\n    return isNaN(n) ? null : n;\n  }\n  function validarFilaExcel(raw) {\n    var out = {};\n    Object.keys(raw).forEach(function (k) { out[normalizeHeader(k)] = raw[k]; });\n    var fecha = parseFechaExcel(out.fecha);\n    if (!fecha) return { ok: false, motivo: 'Fecha inválida o vacía: \"' + (out.fecha || '') + '\"' };\n    var numeroDocumento = String(out.numero_documento || '').trim();\n    if (!numeroDocumento) return { ok: false, motivo: 'Falta número de documento.' };\n    var proveedor = String(out.proveedor || '').trim();\n    if (!proveedor) return { ok: false, motivo: 'Falta proveedor.' };\n    var areaSolicitante = String(out.area_solicitante || '').trim();\n    if (!areaSolicitante) return { ok: false, motivo: 'Falta área solicitante.' };\n    var montoTotal = numExcel(out.monto_total);\n    if (montoTotal == null) return { ok: false, motivo: 'Monto total inválido: \"' + (out.monto_total || '') + '\"' };\n    var montoRetenido = numExcel(out.monto_retenido);\n    if (montoRetenido == null) montoRetenido = 0;\n    return {\n      ok: true,\n      row: {\n        fecha: fecha, numero_documento: numeroDocumento, proveedor: proveedor,\n        descripcion: String(out.descripcion || '').trim(), area_solicitante: areaSolicitante,\n        monto_retenido: montoRetenido, monto_total: montoTotal\n      }\n    };\n  }\n\n  document.getElementById('btnProcesarExcel').addEventListener('click', function () {\n    var msgEl = document.getElementById('excelMsg');\n    hideMsg(msgEl);\n    var file = document.getElementById('gExcelFile').files[0];\n    if (!file) { showMsg(msgEl, 'error', 'Selecciona un archivo primero.'); return; }\n    var reader = new FileReader();\n    reader.onload = function (e) {\n      try {\n        var data = new Uint8Array(e.target.result);\n        var wb = XLSX.read(data, { type: 'array' });\n        var ws = wb.Sheets[wb.SheetNames[0]];\n        var filas = XLSX.utils.sheet_to_json(ws, { raw: true, defval: '' });\n        if (!filas.length) { showMsg(msgEl, 'error', 'El archivo no tiene filas de datos.'); return; }\n\n        filasExcelValidas = [];\n        var previewHtml = '';\n        var ok = 0, err = 0;\n        filas.forEach(function (raw, i) {\n          var v = validarFilaExcel(raw);\n          if (v.ok) { ok++; filasExcelValidas.push(v.row); } else { err++; }\n          previewHtml += '<div class=\"excel-row\">' +\n            '<div class=\"dot ' + (v.ok ? 'ok' : 'error') + '\"></div>' +\n            '<div class=\"txt\">Fila ' + (i + 2) + (v.ok ? ': ' + esc(v.row.proveedor) + ' — $' + money(v.row.monto_total) : '') + '</div>' +\n            (v.ok ? '' : '<div class=\"motivo\">' + esc(v.motivo) + '</div>') +\n            '</div>';\n        });\n\n        document.getElementById('excelPreview').innerHTML = previewHtml;\n        document.getElementById('excelPreviewWrap').style.display = 'block';\n        document.getElementById('excelResumen').style.display = 'flex';\n        document.getElementById('excelResumen').innerHTML =\n          '<div class=\"stat-box\"><div class=\"n\">' + filas.length + '</div><div class=\"l\">Filas leídas</div></div>' +\n          '<div class=\"stat-box\"><div class=\"n\" style=\"color:var(--success)\">' + ok + '</div><div class=\"l\">Válidas</div></div>' +\n          '<div class=\"stat-box\"><div class=\"n\" style=\"color:var(--danger)\">' + err + '</div><div class=\"l\">Con error</div></div>';\n\n        var btnConfirmar = document.getElementById('btnConfirmarExcel');\n        btnConfirmar.style.display = ok ? 'block' : 'none';\n        btnConfirmar.textContent = 'Confirmar e importar ' + ok + ' gasto' + (ok === 1 ? '' : 's') + ' válido' + (ok === 1 ? '' : 's');\n      } catch (err) {\n        showMsg(msgEl, 'error', 'No se pudo leer el archivo: ' + err.message);\n      }\n    };\n    reader.readAsArrayBuffer(file);\n  });\n\n  document.getElementById('btnConfirmarExcel').addEventListener('click', function () {\n    var msgEl = document.getElementById('excelMsg');\n    hideMsg(msgEl);\n    if (!filasExcelValidas.length) return;\n    var btn = this;\n    btn.disabled = true;\n    apiCall('gastos', {\n      method: 'POST',\n      body: { action: 'bulk_save', rows: filasExcelValidas, actor_id: currentUser.ID, actor_nombre: fullName(currentUser) }\n    }).then(function (r) {\n      btn.disabled = false;\n      if (r.ok) {\n        showMsg(msgEl, 'success', r.insertados + ' gasto(s) importado(s) correctamente.' + (r.errores && r.errores.length ? ' ' + r.errores.length + ' fila(s) fueron rechazadas por el servidor.' : ''));\n        filasExcelValidas = [];\n        document.getElementById('btnConfirmarExcel').style.display = 'none';\n        document.getElementById('gExcelFile').value = '';\n        cargarProveedores();\n      } else {\n        showMsg(msgEl, 'error', r.error || 'No se pudo importar el archivo.');\n      }\n    }).catch(function () {\n      btn.disabled = false;\n      showMsg(msgEl, 'error', 'Error de conexión al importar.');\n    });\n  });\n\n  // ==================================================================\n  // Historial\n  // ==================================================================\n  var verTodos = true;\n  var historialGastosRaw = [];\n  document.getElementById('btnVerTodos').addEventListener('click', function () { verTodos = true; loadHistorial(); });\n  document.getElementById('btnVerMios').addEventListener('click', function () { verTodos = false; loadHistorial(); });\n\n  function loadHistorial() {\n    document.getElementById('historialFiltroAdmin').style.display = isAdmin ? 'flex' : 'none';\n    document.getElementById('historialLoading').style.display = 'block';\n    document.getElementById('historialContent').style.display = 'none';\n    var admFlag = isAdmin && verTodos ? '1' : '0';\n    document.getElementById('hRegistradoPorWrap').style.display = admFlag === '1' ? 'block' : 'none';\n    apiCall('gastos?action=list&userId=' + encodeURIComponent(currentUser.ID) + '&admin=' + admFlag).then(function (r) {\n      document.getElementById('historialLoading').style.display = 'none';\n      document.getElementById('historialContent').style.display = 'block';\n      historialGastosRaw = r.gastos || [];\n      poblarRegistradoPorHistorial();\n      aplicarFiltrosHistorial();\n    });\n  }\n\n  function poblarRegistradoPorHistorial() {\n    var sel = document.getElementById('hRegistradoPor');\n    var actual = sel.value;\n    var ids = Array.from(new Set(historialGastosRaw.map(function (g) { return String(g.created_by_id); })));\n    ids.sort(function (a, b) { return nombreDe(a).localeCompare(nombreDe(b)); });\n    sel.innerHTML = '<option value=\"\">Todos</option>' + ids.map(function (id) {\n      return '<option value=\"' + esc(id) + '\">' + esc(nombreDe(id)) + '</option>';\n    }).join('');\n    sel.value = actual;\n  }\n\n  function aplicarFiltrosHistorial() {\n    var fDesde = document.getElementById('hFechaDesde').value;\n    var fHasta = document.getElementById('hFechaHasta').value;\n    var mes = document.getElementById('hMes').value;\n    var registradoPor = document.getElementById('hRegistradoPor').value;\n    var numDoc = document.getElementById('hNumeroDocumento').value.trim().toLowerCase();\n    var proveedor = document.getElementById('hProveedor').value.trim().toLowerCase();\n    var descripcion = document.getElementById('hDescripcion').value.trim().toLowerCase();\n    var area = document.getElementById('hAreaSolicitante').value.trim().toLowerCase();\n    var totalMin = numOrNullCliente(document.getElementById('hMontoTotalMin').value);\n    var totalMax = numOrNullCliente(document.getElementById('hMontoTotalMax').value);\n    var retMin = numOrNullCliente(document.getElementById('hMontoRetenidoMin').value);\n    var retMax = numOrNullCliente(document.getElementById('hMontoRetenidoMax').value);\n\n    var filtrados = historialGastosRaw.filter(function (g) {\n      if (fDesde && g.fecha < fDesde) return false;\n      if (fHasta && g.fecha > fHasta) return false;\n      if (mes && String(g.mes) !== mes) return false;\n      if (registradoPor && String(g.created_by_id) !== registradoPor) return false;\n      if (numDoc && (g.numero_documento || '').toLowerCase().indexOf(numDoc) === -1) return false;\n      if (proveedor && (g.proveedor || '').toLowerCase().indexOf(proveedor) === -1) return false;\n      if (descripcion && (g.descripcion || '').toLowerCase().indexOf(descripcion) === -1) return false;\n      if (area && (g.area_solicitante || '').toLowerCase().indexOf(area) === -1) return false;\n      if (totalMin != null && Number(g.monto_total) < totalMin) return false;\n      if (totalMax != null && Number(g.monto_total) > totalMax) return false;\n      if (retMin != null && Number(g.monto_retenido) < retMin) return false;\n      if (retMax != null && Number(g.monto_retenido) > retMax) return false;\n      return true;\n    });\n    renderHistorial(filtrados);\n  }\n\n  function numOrNullCliente(v) {\n    if (v === '' || v == null) return null;\n    var n = parseFloat(v);\n    return isNaN(n) ? null : n;\n  }\n\n  function limpiarFiltrosHistorial() {\n    ['hFechaDesde', 'hFechaHasta', 'hMes', 'hRegistradoPor', 'hNumeroDocumento', 'hProveedor',\n     'hDescripcion', 'hAreaSolicitante', 'hMontoTotalMin', 'hMontoTotalMax', 'hMontoRetenidoMin', 'hMontoRetenidoMax'\n    ].forEach(function (id) { document.getElementById(id).value = ''; });\n    aplicarFiltrosHistorial();\n  }\n\n  document.getElementById('btnAplicarFiltrosHistorial').addEventListener('click', aplicarFiltrosHistorial);\n  document.getElementById('btnLimpiarFiltrosHistorial').addEventListener('click', limpiarFiltrosHistorial);\n\n  function renderHistorial(gastos) {\n    var el = document.getElementById('historialContent');\n    if (!gastos.length) {\n      el.innerHTML = '<div class=\"empty-state\">' +\n        (historialGastosRaw.length ? 'Ningún gasto coincide con los filtros aplicados.' : 'No hay gastos registrados todavía.') +\n        '</div>';\n      return;\n    }\n    el.innerHTML = gastos.map(function (g) {\n      var puede = isAdmin || String(g.created_by_id) === String(currentUser.ID);\n      var esPropio = String(g.created_by_id) === String(currentUser.ID);\n      return '<div class=\"gasto-item\">' +\n        '<div class=\"gasto-top\">' +\n          '<span>' + esc(g.fecha) + ' · ' + esc(g.numero_documento) + '</span>' +\n          '<span class=\"gasto-total\">$' + money(g.monto_total) + '</span>' +\n        '</div>' +\n        '<div class=\"gasto-line\"><b>' + esc(g.proveedor) + '</b></div>' +\n        '<div class=\"gasto-line\">' + esc(g.descripcion) + '</div>' +\n        '<div class=\"gasto-line\">Área solicitante: ' + esc(g.area_solicitante) + ' · Retenido: $' + money(g.monto_retenido) + '</div>' +\n        (isAdmin ? '<div class=\"gasto-line\">Registrado por: ' + esc(nombreDe(g.created_by_id)) + ' <span class=\"badge ' + (esPropio ? 'propio' : 'ajeno') + '\">' + (esPropio ? 'Yo' : 'Otro usuario') + '</span></div>' : '') +\n        (puede ? '<div class=\"gasto-actions\">' +\n          '<button type=\"button\" class=\"secondary\" data-editar=\"' + g.id + '\">Editar</button>' +\n          '<button type=\"button\" class=\"danger\" data-eliminar=\"' + g.id + '\">Eliminar</button>' +\n        '</div>' : '') +\n        '</div>';\n    }).join('');\n\n    el.querySelectorAll('[data-editar]').forEach(function (btn) {\n      btn.addEventListener('click', function () {\n        var g = gastos.find(function (x) { return String(x.id) === btn.getAttribute('data-editar'); });\n        if (g) cargarGastoEnFormulario(g);\n      });\n    });\n    el.querySelectorAll('[data-eliminar]').forEach(function (btn) {\n      btn.addEventListener('click', function () {\n        var id = btn.getAttribute('data-eliminar');\n        customConfirm('¿Eliminar este gasto? Esta acción no se puede deshacer.', { danger: true, okText: 'Eliminar' }).then(function (ok) {\n          if (!ok) return;\n          apiCall('gastos', { method: 'POST', body: { action: 'delete', id: id, actor_id: currentUser.ID, actor_is_admin: isAdmin } }).then(function (r) {\n            if (r.ok) loadHistorial();\n            else customAlert(r.error || 'No se pudo eliminar el gasto.');\n          });\n        });\n      });\n    });\n  }\n\n  // ==================================================================\n  // Reportes (solo admin)\n  // ==================================================================\n  var reportesInicializado = false;\n  function initReportes() {\n    document.getElementById('reportesLoading').style.display = 'block';\n    document.getElementById('reportesContent').style.display = 'none';\n    apiCall('gastos?action=list&admin=1').then(function (r) {\n      todosLosGastos = r.gastos || [];\n      document.getElementById('reportesLoading').style.display = 'none';\n      document.getElementById('reportesContent').style.display = 'block';\n      if (!reportesInicializado) { poblarFiltrosReporte(); reportesInicializado = true; }\n      aplicarFiltrosReporte();\n    });\n  }\n\n  function poblarFiltrosReporte() {\n    var selUsuario = document.getElementById('repUsuario');\n    var creadores = Array.from(new Set(todosLosGastos.map(function (g) { return String(g.created_by_id); })));\n    creadores.sort(function (a, b) { return nombreDe(a).localeCompare(nombreDe(b)); });\n    creadores.forEach(function (id) {\n      var opt = document.createElement('option');\n      opt.value = id; opt.textContent = nombreDe(id);\n      selUsuario.appendChild(opt);\n    });\n\n    var selCargo = document.getElementById('repCargo');\n    var cargos = Array.from(new Set(creadores.map(function (id) { return getCargo(id); }).filter(function (c) { return c && c !== '—'; })));\n    cargos.sort();\n    cargos.forEach(function (c) {\n      var opt = document.createElement('option');\n      opt.value = c; opt.textContent = c;\n      selCargo.appendChild(opt);\n    });\n\n    var selUnidad = document.getElementById('repUnidad');\n    var unidades = Array.from(new Set(creadores.map(function (id) { return getUnidad(id); }).filter(function (u) { return u && u !== '—'; })));\n    unidades.sort();\n    unidades.forEach(function (u) {\n      var opt = document.createElement('option');\n      opt.value = u; opt.textContent = u;\n      selUnidad.appendChild(opt);\n    });\n  }\n\n  document.getElementById('btnAplicarFiltros').addEventListener('click', aplicarFiltrosReporte);\n\n  function aplicarFiltrosReporte() {\n    var usuario = document.getElementById('repUsuario').value;\n    var cargo = document.getElementById('repCargo').value;\n    var unidad = document.getElementById('repUnidad').value;\n    var desde = document.getElementById('repDesde').value;\n    var hasta = document.getElementById('repHasta').value;\n\n    gastosFiltrados = todosLosGastos.filter(function (g) {\n      if (usuario && String(g.created_by_id) !== usuario) return false;\n      if (cargo && getCargo(g.created_by_id) !== cargo) return false;\n      if (unidad && getUnidad(g.created_by_id) !== unidad) return false;\n      if (desde && g.fecha < desde) return false;\n      if (hasta && g.fecha > hasta) return false;\n      return true;\n    });\n\n    var sumaTotal = gastosFiltrados.reduce(function (s, g) { return s + (Number(g.monto_total) || 0); }, 0);\n    var sumaRetenido = gastosFiltrados.reduce(function (s, g) { return s + (Number(g.monto_retenido) || 0); }, 0);\n    document.getElementById('repStats').innerHTML =\n      '<div class=\"stat-box\"><div class=\"n\">' + gastosFiltrados.length + '</div><div class=\"l\">Gastos</div></div>' +\n      '<div class=\"stat-box\"><div class=\"n\">$' + money(sumaTotal) + '</div><div class=\"l\">Monto total</div></div>' +\n      '<div class=\"stat-box\"><div class=\"n\">$' + money(sumaRetenido) + '</div><div class=\"l\">Monto retenido</div></div>';\n\n    document.getElementById('repTableBody').innerHTML = gastosFiltrados.map(function (g) {\n      return '<tr>' +\n        '<td>' + esc(g.fecha) + '</td><td>' + esc(g.numero_documento) + '</td><td>' + esc(g.proveedor) + '</td>' +\n        '<td>' + esc(g.descripcion) + '</td><td>' + esc(g.area_solicitante) + '</td>' +\n        '<td>$' + money(g.monto_retenido) + '</td><td>$' + money(g.monto_total) + '</td>' +\n        '<td>' + esc(nombreDe(g.created_by_id)) + '</td><td>' + esc(getCargo(g.created_by_id)) + '</td><td>' + esc(getUnidad(g.created_by_id)) + '</td>' +\n        '</tr>';\n    }).join('');\n  }\n\n  document.getElementById('btnExportExcel').addEventListener('click', function () {\n    var data = gastosFiltrados.map(function (g) {\n      return {\n        'Fecha': g.fecha, 'Mes': g.mes, 'N° Documento': g.numero_documento, 'Proveedor': g.proveedor,\n        'Descripción': g.descripcion, 'Área solicitante': g.area_solicitante,\n        'Monto retenido': Number(g.monto_retenido) || 0, 'Monto total': Number(g.monto_total) || 0,\n        'Registrado por': nombreDe(g.created_by_id), 'Cargo': getCargo(g.created_by_id), 'Unidad': getUnidad(g.created_by_id)\n      };\n    });\n    var ws = XLSX.utils.json_to_sheet(data.length ? data : [{}]);\n    var wb = XLSX.utils.book_new();\n    XLSX.utils.book_append_sheet(wb, ws, 'Gastos');\n    XLSX.writeFile(wb, 'Gastos_Baja_Cuantia_' + todayStr() + '.xlsx');\n  });\n\n  document.getElementById('btnExportPDF').addEventListener('click', function () {\n    var jsPDFCtor = (window.jspdf && window.jspdf.jsPDF) || window.jsPDF;\n    var doc = new jsPDFCtor({ unit: 'mm', format: 'letter', orientation: 'landscape' });\n    doc.setFontSize(12);\n    doc.text('Reporte de Gastos de Baja Cuantía', 14, 12);\n    doc.autoTable({\n      startY: 18,\n      head: [['Fecha', 'N° Doc', 'Proveedor', 'Descripción', 'Área solicitante', 'Retenido', 'Total', 'Registrado por', 'Cargo', 'Unidad']],\n      body: gastosFiltrados.map(function (g) {\n        return [g.fecha, g.numero_documento, g.proveedor, g.descripcion, g.area_solicitante,\n          money(g.monto_retenido), money(g.monto_total), nombreDe(g.created_by_id), getCargo(g.created_by_id), getUnidad(g.created_by_id)];\n      }),\n      styles: { fontSize: 7 }\n    });\n    doc.save('Gastos_Baja_Cuantia_' + todayStr() + '.pdf');\n  });\n\n  // ==================================================================\n  // Configurar usuarios / Fondos (solo admin)\n  // ==================================================================\n  var fondos = [];\n  var fondoAsignando = null;\n  var pendingAsignadosIds = [];\n  var TIPO_FONDO_LABEL = { caja_chica: 'Fondo de caja chica', circulante: 'Fondo circulante' };\n\n  function poblarAnios() {\n    var sel = document.getElementById('fAnio');\n    if (sel.options.length) return;\n    var actual = new Date().getFullYear();\n    for (var y = actual - 1; y <= actual + 5; y++) {\n      var opt = document.createElement('option');\n      opt.value = y; opt.textContent = y;\n      if (y === actual) opt.selected = true;\n      sel.appendChild(opt);\n    }\n  }\n\n  function recalcularAutorizacion() {\n    var union = {};\n    fondos.forEach(function (f) { (f.usuario_ids || []).forEach(function (id) { union[String(id)] = true; }); });\n    autorizadosIds = Object.keys(union);\n    canLoad = isAdmin || autorizadosIds.indexOf(String(currentUser.ID)) !== -1;\n    actualizarVisibilidadTabs();\n  }\n\n  function cargarFondos() {\n    document.getElementById('fondosLoading').style.display = 'block';\n    document.getElementById('fondosContent').style.display = 'none';\n    return apiCall('fondos?action=list').then(function (r) {\n      fondos = r.fondos || [];\n      document.getElementById('fondosLoading').style.display = 'none';\n      document.getElementById('fondosContent').style.display = 'block';\n      renderFondos();\n    });\n  }\n\n  function renderFondos() {\n    var el = document.getElementById('fondosContent');\n    if (!fondos.length) {\n      el.innerHTML = '<div class=\"empty-state\">No hay fondos creados todavía.</div>';\n      return;\n    }\n    el.innerHTML = fondos.map(function (f) {\n      var n = (f.usuario_ids || []).length;\n      return '<div class=\"gasto-item\">' +\n        '<div class=\"gasto-top\">' +\n          '<span><b>' + esc(TIPO_FONDO_LABEL[f.tipo] || f.tipo) + '</b> · ' + esc(f.anio) + '</span>' +\n          '<span class=\"gasto-total\">$' + money(f.monto_total) + '</span>' +\n        '</div>' +\n        '<div class=\"gasto-line\">' + n + ' usuario' + (n === 1 ? '' : 's') + ' asignado' + (n === 1 ? '' : 's') +\n          (n ? ': ' + esc(f.usuario_ids.map(nombreDe).join(', ')) : '') +\n        '</div>' +\n        '<div class=\"gasto-actions\">' +\n          '<button type=\"button\" class=\"secondary\" data-asignar=\"' + f.id + '\">Asignar administrador</button>' +\n          '<button type=\"button\" class=\"danger\" data-eliminar-fondo=\"' + f.id + '\">Eliminar</button>' +\n        '</div>' +\n      '</div>';\n    }).join('');\n\n    el.querySelectorAll('[data-asignar]').forEach(function (btn) {\n      btn.addEventListener('click', function () { abrirModalAsignar(btn.getAttribute('data-asignar')); });\n    });\n    el.querySelectorAll('[data-eliminar-fondo]').forEach(function (btn) {\n      btn.addEventListener('click', function () {\n        var id = btn.getAttribute('data-eliminar-fondo');\n        customConfirm('¿Eliminar este fondo? Los usuarios que solo estaban asociados a él perderán acceso al sistema. Esta acción no se puede deshacer.', { danger: true, okText: 'Eliminar' }).then(function (ok) {\n          if (!ok) return;\n          apiCall('fondos', { method: 'POST', body: { action: 'delete', id: id } }).then(function (r) {\n            if (r.ok) { cargarFondos().then(recalcularAutorizacion); } else { customAlert(r.error || 'No se pudo eliminar el fondo.'); }\n          });\n        });\n      });\n    });\n  }\n\n  document.getElementById('btnCrearFondo').addEventListener('click', function () {\n    var msgEl = document.getElementById('fondoMsg');\n    hideMsg(msgEl);\n    var fondo = {\n      tipo: document.getElementById('fTipo').value,\n      monto_total: document.getElementById('fMontoTotal').value,\n      anio: document.getElementById('fAnio').value\n    };\n    if (fondo.monto_total === '' || Number(fondo.monto_total) < 0) {\n      showMsg(msgEl, 'error', 'Ingresa un monto total válido.');\n      return;\n    }\n    var btn = this;\n    btn.disabled = true;\n    apiCall('fondos', { method: 'POST', body: { action: 'create', fondo: fondo } }).then(function (r) {\n      btn.disabled = false;\n      if (r.ok) {\n        showMsg(msgEl, 'success', 'Fondo creado correctamente.');\n        document.getElementById('fMontoTotal').value = '';\n        cargarFondos();\n      } else {\n        showMsg(msgEl, 'error', r.error || 'No se pudo crear el fondo.');\n      }\n    }).catch(function () {\n      btn.disabled = false;\n      showMsg(msgEl, 'error', 'Error de conexión al crear el fondo.');\n    });\n  });\n\n  // ---- Modal: asignar usuarios a un fondo ----\n  function abrirModalAsignar(fondoId) {\n    fondoAsignando = fondos.find(function (f) { return String(f.id) === String(fondoId); });\n    if (!fondoAsignando) return;\n    pendingAsignadosIds = (fondoAsignando.usuario_ids || []).slice();\n    document.getElementById('asignarModalTitle').textContent =\n      'Asignar administrador — ' + (TIPO_FONDO_LABEL[fondoAsignando.tipo] || fondoAsignando.tipo) + ' ' + fondoAsignando.anio;\n    document.getElementById('asignarUserSearch').value = '';\n    hideMsg(document.getElementById('asignarModalMsg'));\n    renderAsignarUserList();\n    document.getElementById('asignarModal').classList.add('open');\n  }\n  function cerrarModalAsignar() {\n    document.getElementById('asignarModal').classList.remove('open');\n    fondoAsignando = null;\n  }\n  document.getElementById('asignarModalCancel').addEventListener('click', cerrarModalAsignar);\n\n  function renderAsignarUserList() {\n    var listEl = document.getElementById('asignarUserList');\n    var filter = (document.getElementById('asignarUserSearch').value || '').toLowerCase();\n    listEl.innerHTML = '';\n    allUsers\n      .filter(function (u) { return fullName(u).toLowerCase().indexOf(filter) !== -1; })\n      .forEach(function (u) {\n        var row = document.createElement('label');\n        row.className = 'user-row';\n        var checked = pendingAsignadosIds.some(function (id) { return String(id) === String(u.ID); });\n        row.innerHTML = '<input type=\"checkbox\" data-id=\"' + u.ID + '\" ' + (checked ? 'checked' : '') + ' /><span>' + esc(fullName(u)) + '</span>';\n        listEl.appendChild(row);\n      });\n  }\n  document.getElementById('asignarUserSearch').addEventListener('input', renderAsignarUserList);\n  document.getElementById('asignarUserList').addEventListener('change', function (ev) {\n    var cb = ev.target;\n    if (cb.tagName !== 'INPUT') return;\n    var id = cb.getAttribute('data-id');\n    if (cb.checked) { if (pendingAsignadosIds.indexOf(id) === -1) pendingAsignadosIds.push(id); }\n    else { pendingAsignadosIds = pendingAsignadosIds.filter(function (x) { return x !== id; }); }\n  });\n\n  document.getElementById('asignarModalGuardar').addEventListener('click', function () {\n    if (!fondoAsignando) return;\n    var msgEl = document.getElementById('asignarModalMsg');\n    var btn = this;\n    btn.disabled = true;\n    apiCall('fondos', { method: 'POST', body: { action: 'asignar', fondo_id: fondoAsignando.id, usuario_ids: pendingAsignadosIds } }).then(function (r) {\n      btn.disabled = false;\n      if (r.ok) {\n        cerrarModalAsignar();\n        cargarFondos().then(recalcularAutorizacion);\n      } else {\n        showMsg(msgEl, 'error', r.error || 'No se pudo guardar la asignación.');\n      }\n    }).catch(function () {\n      btn.disabled = false;\n      showMsg(msgEl, 'error', 'Error de conexión al guardar.');\n    });\n  });\n\n  function initConfigTab() {\n    poblarAnios();\n    cargarFondos();\n  }\n\n  // ==================================================================\n  // Init\n  // ==================================================================\n  function actualizarVisibilidadTabs() {\n    document.getElementById('tabRegistrarBtn').classList.toggle('hidden', !canLoad);\n    document.getElementById('tabExcelBtn').classList.toggle('hidden', !canLoad);\n    document.getElementById('tabHistorialBtn').classList.toggle('hidden', !(canLoad || isAdmin));\n    document.getElementById('tabReportesBtn').classList.toggle('hidden', !isAdmin);\n    document.getElementById('tabConfigBtn').classList.toggle('hidden', !isAdmin);\n  }\n\n  BX24.init(function () {\n    Promise.all([\n      bx('user.current', {}),\n      bx('user.admin', {}),\n      bxListAll('user.get', { FILTER: { ACTIVE: true } }),\n      bxListAll('department.get', {}).catch(function (err) { departamentosError = err; return []; })\n    ]).then(function (results) {\n      currentUser = results[0];\n      isAdmin = !!results[1];\n      allUsers = results[2];\n      allDepartments = results[3];\n      if (departamentosError) console.error('department.get falló:', departamentosError);\n      poblarAreasDesdeDepartamentos();\n      poblarAnios();\n      return apiCall('fondos?action=list');\n    }).then(function (r) {\n      fondos = r.fondos || [];\n      recalcularAutorizacion();\n\n      document.getElementById('viewInicioLoading').style.display = 'none';\n\n      if (canLoad) { activarTab('registrar'); prellenarAreaSolicitante(); cargarProveedores(); }\n      else if (isAdmin) { activarTab('reportes'); }\n      else { document.getElementById('viewSinAcceso').style.display = 'block'; }\n    }).catch(function (err) {\n      document.getElementById('viewInicioLoading').textContent =\n        'Error al iniciar la app: ' + (err && err.ex ? err.ex.error_description : JSON.stringify(err));\n    });\n  });\n})();\n</script>\n</body>\n</html>\n");
};
